"use strict";const Ajv=require("ajv"),fastJsonStringify=require("fast-json-stringify");function ValidatorSelector(){const i=new Map,n=new Map;return n.put=n.set,function(e,r){var t=`${JSON.stringify(e)}${JSON.stringify(r.customOptions)}`;if(i.has(t))return i.get(t);r=ValidatorCompiler(e,r,n);return i.set(t,r),r}}function ValidatorCompiler(e,r,t){const i=new Ajv(Object.assign({coerceTypes:!0,useDefaults:!0,removeAdditional:!0,allErrors:!1,nullable:!0},r.customOptions,{cache:t}));if(r.plugins&&0<r.plugins.length)for(const n of r.plugins)n[0](i,n[1]);for(const o of Object.values(e))i.addSchema(o);return function({schema:e}){if(e.$id){var r=i.getSchema(e.$id);if(r)return r}return i.compile(e)}}function SerializerCompiler(r){return function({schema:e}){return fastJsonStringify(e,{schema:r})}}module.exports.ValidatorSelector=ValidatorSelector,module.exports.SerializerCompiler=SerializerCompiler;